configuration.jsScript:
var currentTime = new Date();
var currentOffset = currentTime.getTimezoneOffset();
var ISTOffset = 330;   // IST offset UTC +5:30 
var ISTTime = new Date(currentTime.getTime() + (ISTOffset + currentOffset)*60000);

// ISTTime now represents the time in IST coordinates

var hoursIST = ISTTime.getHours()
var minutesIST = ISTTime.getMinutes()

var check=minutesIST.toString()

// var checks =check.length()
if (check.length() == 1){
    var minutesIST= "0"+check
}

var curTime = parseInt(hoursIST.toString() + minutesIST.toString());

var startthirtyTime = parseInt(metadata["ss_Plantthirtystarttime"])
var endthirtyTime = parseInt(metadata["ss_Plantthirtyendtime"])

var startfourTime = parseInt(metadata["ss_Plantfourstarttime"])
var endfourTime = parseInt(metadata["ss_Plantfourendtime"])

if (((curTime < startthirtyTime) || (curTime > endthirtyTime)) &&  (msg["Fire Engine Run"] != undefined ) && (msg["Fire Engine Run"] !=metadata["ss_Fire Engine Run"])) {
    return true
}

if (((curTime < startfourTime) || (curTime > endfourTime)) &&  (msg["Fire Engine Run"] != undefined ) && (msg["Fire Engine Run"] !=metadata["ss_Fire Engine Run"])) {
    return true
}
return false

